import React, { useEffect, useRef, useState } from 'react';
import { SERVICES } from '../constants';

const Services: React.FC = () => {
  const sectionRef = useRef<HTMLElement>(null);
  const [scrollProgress, setScrollProgress] = useState(0);

  useEffect(() => {
    const handleScroll = () => {
      if (!sectionRef.current) return;

      const rect = sectionRef.current.getBoundingClientRect();
      const windowHeight = window.innerHeight;

      // Calculate progress: 0 when section enters bottom, 1 when section leaves top
      // Adjusted to make the drawing feel more synced with the middle of the screen
      const start = windowHeight * 0.8; 
      const end = -rect.height * 0.2;
      const totalDistance = start - end;
      const currentPosition = start - rect.top;

      let progress = currentPosition / totalDistance;

      // Clamp between 0 and 1
      if (progress < 0) progress = 0;
      if (progress > 1) progress = 1;

      setScrollProgress(progress);
    };

    window.addEventListener('scroll', handleScroll);
    handleScroll(); // Initial check

    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <section 
      id="services" 
      ref={sectionRef}
      className="py-24 bg-slate-900 relative scroll-mt-24 overflow-hidden"
