import React, { useEffect, useRef, useState } from 'react';

const ScrollProgressLine: React.FC = () => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [scrollProgress, setScrollProgress] = useState(0);

  useEffect(() => {
    const handleScroll = () => {
      if (!containerRef.current) return;

      const element = containerRef.current;
      const rect = element.getBoundingClientRect();
      const windowHeight = window.innerHeight;

      // Calculate scroll progress relative to the container
      // Start filling when the top of the container enters the "active" zone (e.g., 70% down the viewport)
      // Finish filling when the bottom of the container is visible

      const elementTop = rect.top + window.scrollY;
      const elementHeight = rect.height;

      // Adjust these values to control when the drawing starts and ends relative to the viewport
      const startScroll = elementTop - windowHeight * 0.7; 
      const endScroll = (elementTop + elementHeight) - windowHeight * 0.8;

      const distance = endScroll - startScroll;
      const current = window.scrollY - startScroll;

      let progress = current / distance;

      if (progress < 0) progress = 0;
      if (progress > 1) progress = 1;

      setScrollProgress(progress);
    };

    window.addEventListener('scroll', handleScroll);
    window.addEventListener('resize', handleScroll);
    handleScroll();

    return () => {
      window.removeEventListener('scroll', handleScroll);
      window.removeEventListener('resize', handleScroll);
    };
  }, []);

  return (
    <div ref={containerRef} className="absolute inset-0 pointer-events-none overflow-hidden z-0">
      <svg 
        className="w-full h-full" 
        preserveAspectRatio="none"
        viewBox="0 0 100 100"
      >
        <defs>
          <linearGradient id="continuousGradient" x1="0%" y1="0%" x2="0%" y2="100%">
            <stop offset="0%" stopColor="#3b82f6" /> {/* Blue */}
            <stop offset="40%" stopColor="#a855f7" /> {/* Purple */}
            <stop offset="100%" stopColor="#ec4899" /> {/* Pink */}
          </linearGradient>

          <marker 
            id="arrowhead" 
            markerWidth="4" 
            markerHeight="4" 
            refX="2" 
            refY="2" 
            orient="auto"
          >
            <path d="M0,0 L4,2 L0,4" fill="#ec4899" />
          </marker>

          <filter id="glow" x="-20%" y="-20%" width="140%" height="140%">
            <feGaussianBlur stdDeviation="2" result="blur" />
            <feComposite in="SourceGraphic" in2="blur" operator="over" />
          </filter>
        </defs>

        {/* 
          Path Logic: 
          A vertical sine wave (slalom) that spans from top (0) to bottom (100).
          It weaves left and right.
        */}
        {/* Mobile Path (Narrower) */}
        <path 
          d="M 50 0 
             C 20 5, 20 10, 50 15 
             S 80 25, 50 30 
             S 20 40, 50 45 
             S 80 55, 50 60 
             S 20 70, 50 75 
             S 80 85, 50 90 
             S 20 100, 50 100"
          fill="none"
          stroke="#1e293b"
          strokeWidth="2"
          className="lg:hidden"
          vectorEffect="non-scaling-stroke"
        />
         <path 
          d="M 50 0 
             C 20 5, 20 10, 50 15 
             S 80 25, 50 30 
             S 20 40, 50 45 
             S 80 55, 50 60 
             S 20 70, 50 75 
             S 80 85, 50 90 
             S 20 100, 50 100"
          fill="none"
          stroke="url(#continuousGradient)"
          strokeWidth="4"
          className="lg:hidden drop-shadow-[0_0_8px_rgba(168,85,247,0.8)]"
          vectorEffect="non-scaling-stroke"
          pathLength="1"
          strokeDasharray="1"
          strokeDashoffset={1 - scrollProgress}
          strokeLinecap="round"
          markerEnd="url(#arrowhead)"
        />

        {/* Desktop Path (Wider Slalom) */}
        <path 
          d="M 50 0 
             C 20 10, 20 20, 50 25 
             S 80 40, 50 50 
             S 20 70, 50 75 
             S 80 90, 50 100"
          fill="none"
          stroke="#1e293b"
          strokeWidth="2"
          className="hidden lg:block"
          vectorEffect="non-scaling-stroke"
        />
        <path 
          d="M 50 0 
             C 20 10, 20 20, 50 25 
             S 80 40, 50 50 
             S 20 70, 50 75 
             S 80 90, 50 100"
          fill="none"
          stroke="url(#continuousGradient)"
          strokeWidth="5"
          className="hidden lg:block drop-shadow-[0_0_12px_rgba(59,130,246,0.8)]"
          vectorEffect="non-scaling-stroke"
          pathLength="1"
          strokeDasharray="1"
          strokeDashoffset={1 - scrollProgress}
          strokeLinecap="round"
          markerEnd="url(#arrowhead)"
        />
      </svg>
    </div>
  );
};

