const ScrollProgressLine: React.FC = () => {
  const containerRef = useRef<HTMLDivElement>(null);
  const mobilePathRef = useRef<SVGPathElement>(null);
  const desktopPathRef = useRef<SVGPathElement>(null);

  const [scrollState, setScrollState] = useState({
    progress: 0,
    mobile: { x: 50, y: 0, angle: 90 },
    desktop: { x: 50, y: 0, angle: 90 }
  });

  useEffect(() => {
    const handleScroll = () => {
      if (!containerRef.current) return;

      const element = containerRef.current;
      const rect = element.getBoundingClientRect();
      const windowHeight = window.innerHeight;

      // Calculate scroll progress relative to the container
      const elementTop = rect.top + window.scrollY;
      const elementHeight = rect.height;

      const startScroll = elementTop - windowHeight * 0.7; 
      const endScroll = (elementTop + elementHeight) - windowHeight * 0.8;

      const distance = endScroll - startScroll;
      const current = window.scrollY - startScroll;

      let progress = current / distance;

      if (progress < 0) progress = 0;
      if (progress > 1) progress = 1;

      // Calculate position on path for the arrow head
      const newState = { progress, mobile: { ...scrollState.mobile }, desktop: { ...scrollState.desktop } };

      const updatePathPos = (path: SVGPathElement | null, key: 'mobile' | 'desktop') => {
        if (path) {
          const len = path.getTotalLength();
          // Clamp length to avoid errors at exactly 0 or 1 if necessary, though getPointAtLength handles it.
          const point = path.getPointAtLength(len * progress);

          // Calculate angle by looking slightly behind (or ahead if at start)
          const lookBackDist = 1; // 1 SVG unit
          const p1 = point;
          let p2;

          if (len * progress < lookBackDist) {
            // At start: look ahead
             p2 = path.getPointAtLength(Math.min(len, len * progress + lookBackDist));
             // angle from p1 to p2
             newState[key].angle = Math.atan2(p2.y - p1.y, p2.x - p1.x) * (180 / Math.PI);
          } else {
            // Normal: look back
            p2 = path.getPointAtLength(len * progress - lookBackDist);
            // angle from p2 to p1
            newState[key].angle = Math.atan2(p1.y - p2.y, p1.x - p2.x) * (180 / Math.PI);
          }

          newState[key].x = p1.x;
          newState[key].y = p1.y;
        }
      };

      updatePathPos(mobilePathRef.current, 'mobile');
      updatePathPos(desktopPathRef.current, 'desktop');

      setScrollState(newState);
    };

    window.addEventListener('scroll', handleScroll);
    window.addEventListener('resize', handleScroll);

    // Trigger once to set initial state
    handleScroll();

    return () => {
      window.removeEventListener('scroll', handleScroll);
      window.removeEventListener('resize', handleScroll);
    };
  }, []); // Empty deps is fine, refs are stable

