            <stop offset="40%" stopColor="#a855f7" /> {/* Purple */}
            <stop offset="100%" stopColor="#ec4899" /> {/* Pink */}
          </linearGradient>

          {/* Glow Filter for the Head */}
          <filter id="headGlow" x="-50%" y="-50%" width="200%" height="200%">
            <feGaussianBlur stdDeviation="2" result="blur" />
            <feComposite in="SourceGraphic" in2="blur" operator="over" />
          </filter>
        </defs>

        {/* --- MOBILE PATHS --- */}
        <g className="lg:hidden">
            {/* Background Track */}
            <path 
              d="M 50 0 C 20 5, 20 10, 50 15 S 80 25, 50 30 S 20 40, 50 45 S 80 55, 50 60 S 20 70, 50 75 S 80 85, 50 90 S 20 100, 50 100"
              fill="none"
              stroke="#1e293b"
              strokeWidth="2"
              vectorEffect="non-scaling-stroke"
            />
            {/* Progress Track (The glowing line) */}
            <path 
              ref={mobilePathRef}
              d="M 50 0 C 20 5, 20 10, 50 15 S 80 25, 50 30 S 20 40, 50 45 S 80 55, 50 60 S 20 70, 50 75 S 80 85, 50 90 S 20 100, 50 100"
              fill="none"
              stroke="url(#continuousGradient)"
              strokeWidth="4"
              className="drop-shadow-[0_0_8px_rgba(168,85,247,0.8)]"
              vectorEffect="non-scaling-stroke"
              pathLength="1"
              strokeDasharray="1"
              strokeDashoffset={1 - scrollState.progress}
              strokeLinecap="round"
            />
            {/* Moving Arrow Head */}
            <g transform={`translate(${scrollState.mobile.x}, ${scrollState.mobile.y}) rotate(${scrollState.mobile.angle})`}>
                {/* Glow Orb */}
                <circle r="3" fill="#ec4899" filter="url(#headGlow)" opacity="0.8" />
                <circle r="1.5" fill="white" />
                {/* Arrow Shape */}
                <path d="M -2 -2 L 3 0 L -2 2" fill="#ec4899" stroke="white" strokeWidth="0.5" />
            </g>
        </g>

        {/* --- DESKTOP PATHS --- */}
        <g className="hidden lg:block">
            {/* Background Track */}
            <path 
              d="M 50 0 C 20 10, 20 20, 50 25 S 80 40, 50 50 S 20 70, 50 75 S 80 90, 50 100"
              fill="none"
              stroke="#1e293b"
              strokeWidth="2"
              vectorEffect="non-scaling-stroke"
            />
            {/* Progress Track */}
            <path 
              ref={desktopPathRef}
              d="M 50 0 C 20 10, 20 20, 50 25 S 80 40, 50 50 S 20 70, 50 75 S 80 90, 50 100"
              fill="none"
              stroke="url(#continuousGradient)"
              strokeWidth="5"
              className="drop-shadow-[0_0_12px_rgba(59,130,246,0.8)]"
              vectorEffect="non-scaling-stroke"
              pathLength="1"
              strokeDasharray="1"
              strokeDashoffset={1 - scrollState.progress}
              strokeLinecap="round"
            />
             {/* Moving Arrow Head */}
             <g transform={`translate(${scrollState.desktop.x}, ${scrollState.desktop.y}) rotate(${scrollState.desktop.angle})`}>
                {/* Stronger Glow for Desktop */}
                <circle r="2" fill="#ec4899" filter="url(#headGlow)" opacity="0.6" />
                {/* Sharp Arrow */}
                <path d="M -3 -3 L 4 0 L -3 3 L -1 0 Z" fill="#fff" stroke="#ec4899" strokeWidth="1" />
            </g>
        </g>

      </svg>
    </div>
  );
};

