import React, { useEffect, useRef } from 'react';

const ScrollProgressLine: React.FC = () => {
  const containerRef = useRef<HTMLDivElement>(null);

  // Refs for direct DOM manipulation (Performance optimization)
  const mobilePathRef = useRef<SVGPathElement>(null);
  const desktopPathRef = useRef<SVGPathElement>(null);
  const mobileArrowRef = useRef<SVGGElement>(null);
  const desktopArrowRef = useRef<SVGGElement>(null);

  useEffect(() => {
    let ticking = false;

    const updateAnimation = () => {
      if (!containerRef.current) return;

      const element = containerRef.current;
      const rect = element.getBoundingClientRect();
      const windowHeight = window.innerHeight;

      // Calculate scroll progress
      // We start slightly earlier and end slightly later to ensure smooth entrance/exit
      const elementTop = rect.top + window.scrollY;
      const elementHeight = rect.height;

      const startScroll = elementTop - windowHeight * 0.7; 
      const endScroll = (elementTop + elementHeight) - windowHeight * 0.8;

      const distance = endScroll - startScroll;
      const current = window.scrollY - startScroll;

      let progress = current / distance;

      // Clamp progress between 0 and 1
      if (progress < 0) progress = 0;
      if (progress > 1) progress = 1;

      // --- Optimize: Update DOM directly without React Re-renders ---

      // Helper function to update a specific path and arrow
      const updateSet = (
        path: SVGPathElement | null, 
        arrow: SVGGElement | null
      ) => {
        if (!path || !arrow) return;

        // 1. Update Line Progress (Stroke Dashoffset)
        // Since pathLength="1", dashoffset of 0 is full, 1 is empty.
        // We want 1 - progress.
        path.style.strokeDashoffset = (1 - progress).toString();

        // 2. Update Arrow Position & Rotation
        try {
          const len = path.getTotalLength();
          // Get point at current progress
          const point = path.getPointAtLength(len * progress);

          // Calculate rotation
          // Look slightly back (or forward at start) to get tangent
          const lookDist = 1; 
          let p1 = point;
          let p2;
          let angle = 0;

          if (len * progress < lookDist) {
             // Beginning of path: look forward
             p2 = path.getPointAtLength(Math.min(len, len * progress + lookDist));
             angle = Math.atan2(p2.y - p1.y, p2.x - p1.x) * (180 / Math.PI);
          } else {
            // Normal: look backward
            p2 = path.getPointAtLength(len * progress - lookDist);
            angle = Math.atan2(p1.y - p2.y, p1.x - p2.x) * (180 / Math.PI);
          }

          // Apply transform directly
          arrow.setAttribute('transform', `translate(${point.x}, ${point.y}) rotate(${angle})`);

          // Visibility toggle to prevent artifacts at exactly 0
          arrow.style.opacity = progress <= 0.01 ? '0' : '1';

        } catch (e) {
          // Fallback if geometry fails
        }
      };

      // Update Mobile Set
      updateSet(mobilePathRef.current, mobileArrowRef.current);

      // Update Desktop Set
      updateSet(desktopPathRef.current, desktopArrowRef.current);

      ticking = false;
    };

    const onScroll = () => {
      if (!ticking) {
        window.requestAnimationFrame(updateAnimation);
        ticking = true;
      }
    };

    window.addEventListener('scroll', onScroll, { passive: true });
    window.addEventListener('resize', updateAnimation);

    // Initial call
    updateAnimation();

    return () => {
      window.removeEventListener('scroll', onScroll);
      window.removeEventListener('resize', updateAnimation);
    };
  }, []);

  return (
    <div ref={containerRef} className="absolute inset-0 pointer-events-none overflow-hidden z-0">
      <svg 
        className="w-full h-full" 
        preserveAspectRatio="none"
        viewBox="0 0 100 100"
      >
        <defs>
          <linearGradient id="continuousGradient" x1="0%" y1="0%" x2="0%" y2="100%">
            <stop offset="0%" stopColor="#3b82f6" /> {/* Blue */}
            <stop offset="40%" stopColor="#a855f7" /> {/* Purple */}
            <stop offset="100%" stopColor="#ec4899" /> {/* Pink */}
          </linearGradient>

          <filter id="headGlow" x="-50%" y="-50%" width="200%" height="200%">
            <feGaussianBlur stdDeviation="1.5" result="blur" />
            <feComposite in="SourceGraphic" in2="blur" operator="over" />
          </filter>
        </defs>

        {/* --- MOBILE PATHS --- */}
        <g className="lg:hidden">
            <path 
              d="M 50 0 C 20 5, 20 10, 50 15 S 80 25, 50 30 S 20 40, 50 45 S 80 55, 50 60 S 20 70, 50 75 S 80 85, 50 90 S 20 100, 50 100"
              fill="none"
              stroke="#1e293b"
              strokeWidth="2"
              vectorEffect="non-scaling-stroke"
            />
            <path 
              ref={mobilePathRef}
              d="M 50 0 C 20 5, 20 10, 50 15 S 80 25, 50 30 S 20 40, 50 45 S 80 55, 50 60 S 20 70, 50 75 S 80 85, 50 90 S 20 100, 50 100"
              fill="none"
              stroke="url(#continuousGradient)"
              strokeWidth="4"
              className="drop-shadow-[0_0_8px_rgba(168,85,247,0.8)] will-change-[stroke-dashoffset]"
              vectorEffect="non-scaling-stroke"
              pathLength="1"
              strokeDasharray="1"
              strokeDashoffset="1"
              strokeLinecap="round"
            />
            {/* Arrow Group - Directly manipulated via ref */}
            <g ref={mobileArrowRef} className="will-change-transform">
                <circle r="1" fill="#ec4899" filter="url(#headGlow)" opacity="0.6" />
                <path d="M -0.6 -0.6 L 0.9 0 L -0.6 0.6" fill="none" stroke="#ec4899" strokeWidth="0.5" />
            </g>
        </g>

        {/* --- DESKTOP PATHS --- */}
        <g className="hidden lg:block">
            <path 
              d="M 50 0 C 20 10, 20 20, 50 25 S 80 40, 50 50 S 20 70, 50 75 S 80 90, 50 100"
              fill="none"
              stroke="#1e293b"
              strokeWidth="2"
              vectorEffect="non-scaling-stroke"
            />
            <path 
              ref={desktopPathRef}
              d="M 50 0 C 20 10, 20 20, 50 25 S 80 40, 50 50 S 20 70, 50 75 S 80 90, 50 100"
              fill="none"
              stroke="url(#continuousGradient)"
              strokeWidth="5"
              className="drop-shadow-[0_0_12px_rgba(59,130,246,0.8)] will-change-[stroke-dashoffset]"
              vectorEffect="non-scaling-stroke"
              pathLength="1"
              strokeDasharray="1"
              strokeDashoffset="1"
              strokeLinecap="round"
            />
             {/* Arrow Group - Directly manipulated via ref */}
             <g ref={desktopArrowRef} className="will-change-transform">
                <circle r="1.5" fill="#ec4899" filter="url(#headGlow)" opacity="0.4" />
                <path d="M -0.9 -0.9 L 1.2 0 L -0.9 0.9 L -0.3 0 Z" fill="#0f172a" stroke="#ec4899" strokeWidth="0.5" />
            </g>
        </g>

      </svg>
    </div>
  );
};

